<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 16px;
  }
  h1 { font-size: 3rem; font-weight: 700; color: #e0c060; }
  #ui { display: flex; align-items: center; gap: 24px; }
  #score-box {
    background: #16213e;
    border: 2px solid #e0c060;
    border-radius: 8px;
    padding: 8px 20px;
    text-align: center;
  }
  #score-box .label { font-size: 0.75rem; color: #aaa; text-transform: uppercase; }
  #score { font-size: 1.6rem; font-weight: 700; color: #e0c060; }
  #reset {
    background: #e0c060;
    color: #1a1a2e;
    border: none;
    border-radius: 8px;
    padding: 10px 22px;
    font-size: 1rem;
    font-weight: 700;
    cursor: pointer;
    transition: background 0.15s;
  }
  #reset:hover { background: #c8a840; }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 90px);
    grid-template-rows: repeat(4, 90px);
    gap: 10px;
    background: #0f3460;
    border-radius: 10px;
    padding: 10px;
  }
  .cell {
    width: 90px;
    height: 90px;
    border-radius: 6px;
    background: #16213e;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.8rem;
    font-weight: 700;
    transition: background 0.1s;
  }
  .cell[data-val="0"] { background: #16213e; color: transparent; }
  .cell[data-val="2"]    { background: #3a7bd5; color: #fff; }
  .cell[data-val="4"]    { background: #3a60c0; color: #fff; }
  .cell[data-val="8"]    { background: #e07840; color: #fff; }
  .cell[data-val="16"]   { background: #e05820; color: #fff; }
  .cell[data-val="32"]   { background: #e03010; color: #fff; }
  .cell[data-val="64"]   { background: #c02000; color: #fff; }
  .cell[data-val="128"]  { background: #e0c030; color: #fff; font-size: 1.5rem; }
  .cell[data-val="256"]  { background: #e0b800; color: #fff; font-size: 1.5rem; }
  .cell[data-val="512"]  { background: #e0a000; color: #fff; font-size: 1.5rem; }
  .cell[data-val="1024"] { background: #d08000; color: #fff; font-size: 1.2rem; }
  .cell[data-val="2048"] { background: #c06000; color: #fff; font-size: 1.2rem; }
</style>
</head>
<body>
<h1>2048</h1>
<div id="ui">
  <div id="score-box"><div class="label">Score</div><div id="score">0</div></div>
  <button id="reset">New Game</button>
</div>
<div id="board"></div>
<script>
(function() {
  const SIZE = 4;
  let grid = [];
  let currentScore = 0;

  function emptyGrid() {
    return Array.from({length: SIZE}, () => new Array(SIZE).fill(0));
  }

  function emptycells(g) {
    const cells = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (g[r][c] === 0) cells.push([r, c]);
    return cells;
  }

  function spawnTile(g) {
    const empty = emptyCells(g);
    if (!empty.length) return;
    const [r, c] = empty[Math.floor(Math.random() * empty.length)];
    g[r][c] = Math.random() < 0.9 ? 2 : 4;
  }

  function slideRow(row) {
    // Compress non-zero
    let tiles = row.filter(v => v !== 0);
    let merged = new Array(tiles.length).fill(false);
    let score = 0;
    for (let i = 0; i < tiles.length - 1; i++) {
      if (!merged[i] && tiles[i] === tiles[i+1]) {
        tiles[i] *= 2;
        score += tiles[i];
        tiles.splice(i+1, 1);
        merged.splice(i+1, 1);
        merged[i] = true;
      }
    }
    while (tiles.length < SIZE) tiles.push(0);
    return { row: tiles, score };
  }

  function applyMove(direction) {
    let totalScore = 0;
    let changed = false;

    if (direction === 'left') {
      for (let r = 0; r < SIZE; r++) {
        const { row, score } = slideRow(grid[r].slice());
        if (row.join(',') !== grid[r].join(',')) changed = true;
        grid[r] = row;
        totalScore += score;
      }
    } else if (direction === 'right') {
      for (let r = 0; r < SIZE; r++) {
        const { row, score } = slideRow(grid[r].slice().reverse());
        const newRow = row.reverse();
        if (newRow.join(',') !== grid[r].join(',')) changed = true;
        grid[r] = newRow;
        totalScore += score;
      }
    } else if (direction === 'up') {
      for (let c = 0; c < SIZE; c++) {
        const col = grid.map(row => row[c]);
        const { row, score } = slideRow(col);
        for (let r = 0; r < SIZE; r++) {
          if (grid[r][c] !== row[r]) changed = true;
          grid[r][c] = row[r];
        }
        totalScore += score;
      }
    } else if (direction === 'down') {
      for (let c = 0; c < SIZE; c++) {
        const col = grid.map(row => row[c]).reverse();
        const { row, score } = slideRow(col);
        const newCol = row.reverse();
        for (let r = 0; r < SIZE; r++) {
          if (grid[r][c] !== newCol[r]) changed = true;
          grid[r][c] = newCol[r];
        }
        totalScore += score;
      }
    }

    return { changed, score: totalScore };
  }

  function render() {
    const board = document.getElementById('board');
    board.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const val = grid[r][c];
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.val = val;
        cell.textContent = val !== 0 ? val : '';
        board.appendChild(cell);
      }
    }
    document.getElementById('score').textContent = currentScore;
  }

  function newGame() {
    grid = emptyGrid();
    currentScore = 0;
    spawnTile(grid);
    spawnTile(grid);
    render();
  }

  document.getElementById('reset').addEventListener('click', newGame);

  document.addEventListener('keydown', e => {
    const map = {
      ArrowLeft: 'left', ArrowRight: 'right',
      ArrowUp: 'up', ArrowDown: 'down'
    };
    const dir = map[e.key];
    if (!dir) return;
    e.preventDefault();
    const { changed, score } = applyMove(dir);
    if (changed) {
      currentScore += score;
      spawnTile(grid);
      render();
    }
  });

  window.game = {
    size: SIZE,
    reset() { newGame(); },
    move(direction) {
      const { changed, score } = applyMove(direction);
      if (changed) {
        currentScore += score;
        spawnTile(grid);
        render();
      }
      return changed;
    },
    board() {
      return grid.map(row => row.slice());
    },
    setBoard(arr) {
      grid = arr.map(row => row.slice());
      render();
    },
    score() { return currentScore; }
  };

  newGame();
})();
</script>
</body>
</html>
